const body = $input.first().json.body || $input.first().json;

const topic = body.topic || 'everyday';
const topicDesc = body.topic_desc || 'everyday life';
const level = body.level || 'A1';
const history = body.history || [];

const types = ['multiple_choice', 'fill_blank', 'translation_fr_to_en'];
const lastType = history.length ? history[history.length - 1].type : null;
const available = types.filter(t => t !== lastType);
const type = available[Math.floor(Math.random() * available.length)];

const recent = history.slice(-6);
const correctRate = recent.length > 0
  ? recent.filter(h => h.correct === true).length / recent.length
  : 0.5;

let difficultyNote = 'Standard difficulty for this level.';
if (correctRate >= 0.8 && recent.length >= 4) {
  difficultyNote = 'The student is doing very well. Make the exercise slightly harder, use less common vocabulary.';
} else if (correctRate <= 0.3 && recent.length >= 4) {
  difficultyNote = 'The student is struggling. Make the exercise easier, use very common everyday words only.';
}

const typeSpec = {
  multiple_choice: '"options": array of exactly 4 short strings (no A) B) prefix), "correct_index": integer 0-3. The 3 wrong answers must be plausible but clearly wrong — not random gibberish.',
  fill_blank: '"sentence_before": string, "sentence_after": string (can be ""), "answer": the ONE missing English word (not a phrase), "hint_fr": the EXACT French translation of the missing word — just the word itself, nothing else. Example: if answer is "today", hint_fr must be "aujourd\'hui". If answer is "open", hint_fr must be "ouvert(e)".',
  translation_fr_to_en: '"french_text": a short practical French sentence (max 8 words), "answer_en": main correct English translation, "accepted_variants": array of 2-3 acceptable English alternatives'
};

const qualityRules = `
QUALITY RULES — mandatory:
- For fill_blank: the blank must test a real vocabulary word the student needs to learn. The hint_fr must be the direct French translation of the answer word — nothing more, nothing less. Never use vague hints like "maintenant / ce jour".
- For multiple_choice: the question must test real knowledge, not just recall a fixed phrase. Wrong options must be believable.
- For translation_fr_to_en: use practical sentences a person would actually say or write.
- Never generate trivial exercises where the answer is obvious without knowing English.
- Always make the exercise genuinely useful for a beginner learning English in real life.`;

const prompt = `You are an English teacher for a French adult beginner at level ${level}.
Generate ONE English learning exercise.

Topic area: ${topicDesc}
Exercise type: ${type}
Difficulty note: ${difficultyNote}
${qualityRules}

Required JSON fields for type "${type}": ${typeSpec[type]}

Also always include:
- "type": "${type}"
- "question_en": exercise instruction in English (short, clear)
- "question_fr_hint": French explanation of what is asked — must be clear and useful for a beginner (1 sentence)
- "explanation_fr": 1-2 sentences in French explaining why the answer is correct + one concrete grammar or vocabulary tip
- "explanation_en": same explanation in English (used for text-to-speech audio feedback)
- "adapted": true if you adjusted difficulty based on performance, false otherwise

Respond ONLY with valid compact JSON. No markdown. No extra text. No comments.`;

return [{ json: { prompt, type, level, topic } }];

const agentOutput = $input.first().json;

// Le noeud AI Agent natif n8n retourne la reponse dans .output
const raw = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);

try {
  const clean = raw.replace(/```json|```/g, '').trim();
  const exercise = JSON.parse(clean);

  const required = ['type', 'question_en', 'question_fr_hint', 'explanation_fr', 'explanation_en'];
  for (const field of required) {
    if (!exercise[field]) throw new Error('Champ manquant : ' + field);
  }

  exercise._valid = true;
  return [{ json: exercise }];

} catch(e) {
  return [{ json: {
    type: 'multiple_choice',
    question_en: 'What do you say when you meet someone for the first time?',
    question_fr_hint: 'Que dit-on quand on rencontre quelquun pour la premiere fois ?',
    options: ['Nice to meet you', 'See you later', 'Good night', 'Thank you'],
    correct_index: 0,
    explanation_fr: 'Nice to meet you signifie enchante — formule standard lors dune premiere rencontre.',
    explanation_en: 'Nice to meet you is the standard phrase when meeting someone for the first time.',
    adapted: false,
    _valid: false,
    _error: e.message,
    _raw: raw.substring(0, 200)
  }}];
}
